// TODO rename to "volatileCopy"
void vmemcpy(volatile void *dest, const volatile void *src, volatile uint64_t count) {
	uint8_t *dst8 = (uint8_t *)dest;
	uint8_t *src8 = (uint8_t *)src;

	while (count--) {
		*dst8++ = *src8++;
	}
}

void *tmemcpy(void *dest, const void *src, uint64_t count) {
	// Handle edge cases
	if (count == 0 || dest == src) {
		return dest;
	}
    uint8_t *dst = (uint8_t *)dest;
    const uint8_t *src8 = (const uint8_t *)src;
	// Align destination to 16-byte boundary for SIMD
	while (((uintptr_t)dst & 15) && count) {
		*dst++ = *src8++;
		count--;
	}
	// Use 64-bit copies for unaligned or non-SIMD cases
	if (count >= 8 && !((uintptr_t)src8 & 7)) {
		uint64_t* dst64 = (uint64_t*)dst;
		const uint64_t* src64 = (const uint64_t*)src8;
		while (count >= 8) {
			*dst64++ = *src64++;
			count -= 8;
		}
		dst = (uint8_t*)dst64;
		src8 = (const uint8_t*)src64;
	}
	// Use SSE2 for large, aligned blocks
	/*if (count >= 16) {
		__m128i* dst128 = (__m128i*)dst;
		const __m128i* src128 = (const __m128i*)src8;
		while (count >= 16) {
			_mm_store_si128(dst128++, _mm_loadu_si128(src128++));
			count -= 16;
		}
		dst = (uint8_t*)dst128;
		src8 = (const uint8_t*)src128;
	}*/
	// Copy remaining bytes
    while (count--) {
        *dst++ = *src8++;
    }
    return dest;
}

