#define STBI_VERSION 1

enum {
	STBI_default = 0, // only used for desired_channels

	STBI_grey = 1,
	STBI_grey_alpha = 2,
	STBI_rgb = 3,
	STBI_rgb_alpha = 4
};

typedef uint8_t stbi_uc;
typedef uint16_t stbi_us;

